VALUES
  ('dietitian-moex-04294', 'dietitian', 'dietitian-moex-113-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '有關冷凍食品的特性和應用之敘述，下列何者錯誤？', '["冷凍裹粉產品可在凍結狀態下直接下鍋油炸，但一次下鍋量不宜過多以免油溫驟降影響品質", "部分小體積的冷凍調理食品（例如湯圓等）可不需解凍直接加熱調理", "冷凍肉品的保存期限通常較冷藏肉品更長", "冷凍肉品如需緊急使用，可在包裝完整的情形下浸泡於流動之溫熱水中加速解凍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "03b3b9574c4e", "answer_pdf_sha1": "514f30d8b62b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
